    bytes32 internal constant _WITHDRAW_FROM_BOX_MESSAGE = keccak256(
        "WithdrawFromBoxMessage("
            "address root,"
            "uint32 boxId,"
            "address token,"
            "uint256 amount,"
            //
            "uint64 expiry,"
            "uint256 salt"
        ")"
