    // prettier-ignore
    bytes32 internal constant _OTC_TRADE_REQ = keccak256(
        "OTCTradeReq("
            "uint24 marketId,"
            "int128 signedSize,"
            "int128 rate,"
            "address maker,"
            "address taker,"
