        bool cross;
        AMMId ammId;
        bool enterMarket;
        int256 netCashIn;
        uint256 minLpOut;
        Side desiredSwapSide;
        int128 desiredSwapRate;
    }

    struct RemoveLiquidityDualFromAmmReq {
        bool cross;
        AMMId ammId;
        uint256 lpToRemove;
        int256 minCashOut;
        int256 minSizeOut;
