        Account account;
        bool cross;
        MarketId marketId;
        Side side;
        TimeInForce tif;
        uint256 size;
        int16 tick;
        bool reduceOnly;
        uint256 salt;
        uint64 expiry;
        bytes32 hashedOffchainCondition;
